import javax.servlet.*;
import javax.servlet.http.*;
import java.io.*;

public class java_46568_SessionManager_A03 extends HttpServlet {  // Create a servlet (similar to controller in MVC) extending from the HTTP Servlet base that handles requests and responses of type 'Http'. We're using it here for session management & CSRF protection, among other things... but this example doesn’t use them
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException { }  // Do nothing because we are not processing a form in POST. If you have one defined here also that method would be called after the GET/POST is handled  
    
    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {      
        // Start by creating an instance of a SessionManager if it doesn't exist yet. (Session Manager = new Singleton pattern with only one object).  -1 indicates no maximum size for the session and is shared across all users in any case; thus we use cookie to hold user data, which will be automatically deleted after browser close
        HttpSession sessionMgr =  request.getSession(true); // if true then creates a new SessionID/session object otherwise retrieves an existing one  -1 indicates no maximum size for the session and is shared across all users in any case; thus we use cookie to hold user data, which will be automatically deleted after browser close
        response.setContentType("text/html"); // set content type as HTML  
         if (sessionMgr.isNew()){  // checking new or not newly created session      -1 indicates no maximum size for the sessions and is shared across all users in any case; thus we use cookie to hold user data, which will be automatically deleted after browser close   
            PrintWriter out = response.getWriter();   // get a writer object of ServletResponse(HttpServlet Response)  used as an interface over HttpOutputStream where the servlets can deliver page content and handle requests with http request & responses by setting HTTP headers to clients, in this case we're printing HTML directly into browser
            out.println("<html>");   // opening tag for html body    -1 indicates no maximum size of tags allowed on a single line; thus uses string pool     String Pool:  A special kind memory area used by Java Virtual Machine that stores strings which can be reused, significantly enhancing efficiency and speeding up the program
            out.println("<body>");   // opening tag for body    -1 indicates no maximum size of tags allowed on a single line; thus uses string pool     String Pool:  A special kind memory area used by Java Virtual Machine that stores strings which can be reused, significantly enhancing efficiency and speeding up the program
            out.println("<h2>Welcome to our session management example! </h2>");   // HTML content    -1 indicates no maximum size of tags allowed on a single line; thus uses string pool     String Pool:  A special kind memory area used by Java Virtual Machine that stores strings which can be reused, significantly enhancing efficiency and speeding up the program
            out.println("</body></html>");   // closing tag for body & html    -1 indicates no maximum size of tags allowed on a single line; thus uses string pool     String Pool:  A special kind memory area used by Java Virtual Machine that stores strings which can be reused, significantly enhancing efficiency and speeding up the program
        } else {   // if session exists then print from there. If not new one is created it will show this message for now using out writer object in response to client request  -1 indicates no maximum size of tags allowed on a single line; thus uses string pool     String Pool: A special kind memory area used by Java Virtual Machine that stores strings which can be reused, significantly enhancing efficiency and speeding up the program
            PrintWriter out =response.getWriter();   // get an object for HTTPServletResponse(Http Servlet Response), it is similar to HttpOutputStream where servlets deliver content of page through http requests & responses using setting headers in clients  -1 indicates no maximum size tags allowed on a single line; thus uses string pool     String Pool: A special kind memory area used by Java Virtual Machine that stores strings which can be reused, significantly enhancing efficiency and speeding up the program
            out.println("<html><body>");   // opening tag for body    -1 indicates no maximum size of tags allowed on a single line; thus uses string pool     String Pool: A special kind memory area used by Java Virtual Machine that stores strings which can be reused, significantly enhancing efficiency and speeding up the program
            out.println("Welcome back to our session management example!");   // HTML content    -1 indicates no maximum size of tags allowed on a single line; thus uses string pool     String Pool: A special kind memory area used by Java Virtual Machine that stores strings which can be reused, significantly enhancing efficiency and speeding up the program
            out.println("</body></html>");   // closing tag for body & html    -1 indicates no maximum size of tags allowed on a single line; thus uses string pool     String Pool: A special kind memory area used by Java Virtual Machine that stores strings which can be reused, significantly enhancing efficiency and speeding up the program
        }  // end else block handling both cases (if session exists or not)    -1 indicates no maximum size of tags allowed on a single line; thus uses string pool     String Pool: A special kind memory area used by Java Virtual Machine that stores strings which can be reused, significantly enhancing efficiency and speeding up the program
        out.close();  // closing writer object to prevent resource leaks   -1 indicates no maximum size of tags allowed on a single line; thus uses string pool     String Pool: A special kind memory area used by Java Virtual Machine that stores strings which can be reused, significantly enhancing efficiency and speeding up the program
    }  // end doGet block handling both cases (if session exists or not)   -1 indicates no maximum size of tags allowed on a single line; thus uses string pool     String Pool: A special kind memory area used by Java Virtual Machine that stores strings which can be reused, significantly enhancing efficiency and speeding up the program
}  // end class definition SSMExample    -1 indicates no maximum size for this comment or code. Thus it does not cause any issues with compilation   String Pool: A special kind memory area used by Java Virtual Machine that stores strings which can be reused, significantly enhancing efficiency and speeding up the program